worked_example.final_code:
import java.util.*;
import java.util.function.*;

class Pair<A, B> {
    final A first; final B second;
    Pair(A a, B b) { first=a; second=b; }
    public String toString() { return "(" + first + ", " + second + ")"; }
}

public class GenericUtils {
    public static <T> T firstOrDefault(List<T> list, T def) {
        return list.isEmpty() ? def : list.get(0);
    }

    public static <T> List<T> repeat(T value, int times) {
        List<T> r = new ArrayList<>(times);
        for (int i = 0; i < times; i++) r.add(value);
        return r;
    }

    public static <A, B> List<Pair<A, B>> zip(List<A> as, List<B> bs) {
        int size = Math.min(as.size(), bs.size());
        List<Pair<A, B>> r = new ArrayList<>(size);
        for (int i = 0; i < size; i++) r.add(new Pair<>(as.get(i), bs.get(i)));
        return r;
    }

    public static <T> T requireNonNull(T value, String name) {
        if (value == null) throw new NullPointerException(name + " must not be null");
        return value;
    }

    public static <T, R> List<R> transform(List<T> list, Function<T, R> fn) {
        List<R> r = new ArrayList<>(list.size());
        for (T item : list) r.add(fn.apply(item));
        return r;
    }

    public static <T> Optional<T> findFirst(List<T> list, Predicate<T> p) {
        for (T item : list) if (p.test(item)) return Optional.of(item);
        return Optional.empty();
    }

    public static void main(String[] args) {
        List<String>  names  = Arrays.asList("Aisha", "Raj", "Priya");
        List<Integer> scores = Arrays.asList(95, 87, 92);

        System.out.println(firstOrDefault(names, "none"));
        System.out.println(repeat(0, 4));
        System.out.println(zip(names, scores));
        System.out.println(transform(names, String::toUpperCase));
        System.out.println(transform(names, String::length));
        System.out.println(findFirst(names, s -> s.length() > 4));
    }
}

